void OnTick() {

   // ── OGNI TICK: CheckPartialTP e ManageTrailingStructural ──
   // Girano su ogni tick per vedere H/L intrabar (Model=1).
   // Layer5 ha gate interni M15/H1 che altrimenti li bloccherebbero.
   for(int j = 0; j < activeSymbolCount; j++) {
      string sym = activeSymbols[j];
      int idx = GetSymbolIndex(sym);
      if(idx < 0 || !symbolStates[idx].systemActive) continue;
      int dir = symbolStates[j].direction;
      if(dir != 0) {
         CheckPartialTP(sym, dir);
         ManageTrailingStructural(sym, dir);
      }
   }

   // ── GATE M15 — entry logic solo su nuova candela M15 ──
